15	/* ============================================================================
16	 * Internal Helper
17	 * ========================================================================== */
18	
19	/**
20	 * @brief Split a 16-bit address into MSB/LSB bytes (big-endian, as required by
21	 *        all multi-byte address parameters in the ILI9488 command set).
22	 */
23	static inline void _address_to_bytes(uint16_t address,
24	                                      uint8_t *msb_byte,
25	                                      uint8_t *lsb_byte)
26	{
27	    *msb_byte = (uint8_t)((address >> 8) & 0xFF);
28	    *lsb_byte = (uint8_t)(address & 0xFF);
29	}
