31	/* ============================================================================
32	 * Cached Register State
33	 * ========================================================================== */
34	
35	/** Last written value of Memory Access Control register (0x36) */
36	static uint8_t g_current_mac_register = 0x00;
37	
38	/** Last configured pixel format */
39	static hal_pixel_format_t g_current_pixel_format = PIXEL_FORMAT_16BIT;
