41	/* ============================================================================
42	 * Initialization & Configuration
43	 * ========================================================================== */
44	
45	bool hal_display_initialize(hal_pixel_format_t pixel_format,
46	                            hal_rotation_t rotation)
47	{
48	    /* Hardware reset sequence — Datasheet Section 11 (Power On/Off Sequence) */
49	    spi_gpio_set_state(GPIO_RESET, GPIO_STATE_LOW);
50	    spi_delay_ms(1);
51	    spi_gpio_set_state(GPIO_RESET, GPIO_STATE_HIGH);
52	    spi_delay_ms(120);
53	
54	    /* Software reset — Datasheet Section 5.2.2 (0x01) */
55	    if (!spi_transmit_command(0x01)) return false;
56	    spi_delay_ms(5);
57	
58	    /* Sleep out — Datasheet Section 5.2.13 (0x11) */
59	    if (!spi_transmit_command(0x11)) return false;
60	    spi_delay_ms(120);
61	
62	    /* Pixel format and rotation */
63	    if (!hal_pixel_format_set(pixel_format)) return false;
64	    if (!hal_display_rotation_set(rotation,
65	                                   HORIZONAL_DIRECTION_DEFAULT,
66	                                   VERTICAL_DIRECTION_DEFAULT)) return false;
67	
68	    /* Power supply configuration — Datasheet Section 5.3.12–5.3.17 */
69	    if (!hal_power_gvdd_set(0x17)) return false;
70	    if (!hal_power_vci_set(0x41)) return false;
71	    if (!hal_power_vgh_vgl_set(0x0A, 0x0A)) return false;
72	    if (!hal_power_vcomh_set(0x30)) return false;
73	
74	    /* Frame rate — Datasheet Section 5.3.2 (0xB1) */
75	    if (!hal_frame_rate_set(0x18)) return false;
76	
77	    /* Gamma — Datasheet Section 5.2.26 (0x26) */
78	    if (!hal_gamma_curve_select(GAMMA_CURVE_3)) return false;
79	
80	    /* Full-screen address window */
81	    if (!hal_column_address_set(0, 319)) return false;
82	    if (!hal_row_address_set(0, 479)) return false;
83	
84	    /* Normal display mode — Datasheet Section 5.2.15 (0x13) */
85	    if (!hal_normal_display_mode_on()) return false;
86	
87	    /* Display on — Datasheet Section 5.2.21 (0x29) */
88	    if (!hal_display_output_control(true)) return false;
89	    spi_delay_ms(10);
90	
91	    return true;
92	}
93	
94	bool hal_display_deinitialize(void)
95	{
96	    if (!hal_display_output_control(false)) return false;
97	    spi_delay_ms(5);
98	    if (!hal_power_sleep_mode_set(true)) return false;
99	    return true;
100	}
