102	/* ============================================================================
103	 * System Control Commands
104	 * ========================================================================== */
105	
106	bool hal_system_reset(hal_reset_scope_t reset_scope)
107	{
108	    /* Software Reset — Datasheet Section 5.2.2 (0x01) */
109	    (void)reset_scope;
110	
111	    if (!spi_transmit_command(0x01)) return false;
112	    spi_delay_ms(5);
113	    return true;
114	}
