116	bool hal_power_sleep_mode_set(bool enable)
117	{
118	    if (enable) {
119	        /* Sleep In — Datasheet Section 5.2.12 (0x10) */
120	        if (!spi_transmit_command(0x10)) return false;
121	        spi_delay_ms(5);
122	    } else {
123	        /* Sleep Out — Datasheet Section 5.2.13 (0x11) */
124	        if (!spi_transmit_command(0x11)) return false;
125	        spi_delay_ms(120);
126	    }
127	    return true;
128	}
129	
130	bool hal_power_sleep_exit(void)
131	{
132	    /* Sleep Out — Datasheet Section 5.2.13 (0x11) */
133	    if (!spi_transmit_command(0x11)) return false;
134	    spi_delay_ms(120);
135	    return true;
136	}
