138	bool hal_display_output_control(bool enabled)
139	{
140	    /* Display On (0x29) / Display Off (0x28) — Datasheet Section 5.2.20–5.2.21 */
141	    uint8_t command = enabled ? 0x29 : 0x28;
142	    return spi_transmit_command(command);
143	}
