145	bool hal_power_set_state(hal_power_state_t power_state)
146	{
147	    switch (power_state) {
148	        case POWER_STATE_SLEEP:
149	            return hal_power_sleep_mode_set(true);
150	
151	        case POWER_STATE_NORMAL:
152	            hal_power_sleep_exit();
153	            return hal_display_output_control(true);
154	
155	        case POWER_STATE_DISPLAY_OFF:
156	            return hal_display_output_control(false);
157	
158	        default:
159	            return false;
160	    }
161	}
