163	/* ============================================================================
164	 * Display Configuration Commands
165	 * ========================================================================== */
166	
167	bool hal_pixel_format_set(hal_pixel_format_t pixel_format)
168	{
169	    /* Interface Pixel Format — Datasheet Section 5.2.34 (0x3A)
170	     * 0x03 = 12-bit, 0x05 = 16-bit RGB565, 0x06 = 18-bit */
171	    uint8_t param = (uint8_t)pixel_format;
172	
173	    if (!spi_transmit_command(0x3A)) return false;
174	    if (!spi_transmit_data(&param, 1)) return false;
175	
176	    g_current_pixel_format = pixel_format;
177	    return true;
178	}
179	
180	bool hal_display_rotation_set(hal_rotation_t rotation,
181	                              hal_horizontal_direction_t horizontal_flip,
182	                              hal_vertical_direction_t vertical_flip)
183	{
184	    /* Memory Access Control — Datasheet Section 5.2.30 (0x36)
185	     * Bit 7 (MY): row direction, Bit 6 (MX): col direction, Bit 5 (MV): row/col swap
186	     * Bit 4 (ML): vertical order,  Bit 3 (BGR): colour order */
187	    uint8_t mac_byte;
188	
189	    switch (rotation) {
190	        case ROTATION_0_NORMAL:             mac_byte = 0x00; break;
191	        case ROTATION_90_CLOCKWISE:         mac_byte = 0x60; break;
192	        case ROTATION_180_INVERSE:          mac_byte = 0xC0; break;
193	        case ROTATION_270_COUNTERCLOKWISE:  mac_byte = 0xA0; break;
194	        default:                            return false;
195	    }
196	
197	    if (horizontal_flip == HORIZONAL_DIRECTION_REVERSED) mac_byte ^= 0x40;
198	    if (vertical_flip   == VERTICAL_DIRECTION_REVERSED)  mac_byte ^= 0x80;
199	
200	    if (!spi_transmit_command(0x36)) return false;
201	    if (!spi_transmit_data(&mac_byte, 1)) return false;
202	
203	    g_current_mac_register = mac_byte;
204	    return true;
205	}
206	
207	bool hal_color_byte_order_set(hal_byte_order_t byte_order)
208	{
209	    /* Memory Access Control — Bit 3 (BGR) — Datasheet Section 5.2.30 (0x36) */
210	    uint8_t mac_byte = g_current_mac_register;
211	
212	    if (byte_order == BYTE_ORDER_BGR) {
213	        mac_byte |= 0x08;
214	    } else {
215	        mac_byte &= (uint8_t)~0x08;
216	    }
217	
218	    if (!spi_transmit_command(0x36)) return false;
219	    if (!spi_transmit_data(&mac_byte, 1)) return false;
220	
221	    g_current_mac_register = mac_byte;
222	    return true;
223	}
224	
225	bool hal_transfer_mode_set(hal_transfer_mode_t transfer_mode)
226	{
227	    /* Memory Access Control — Bit 5 (MV) — Datasheet Section 5.2.30 (0x36) */
228	    uint8_t mac_byte = g_current_mac_register;
229	
230	    if (transfer_mode == TRANSFER_MODE_PAGE_ADDRESS) {
231	        mac_byte |= 0x20;
232	    } else {
233	        mac_byte &= (uint8_t)~0x20;
234	    }
235	
236	    if (!spi_transmit_command(0x36)) return false;
237	    if (!spi_transmit_data(&mac_byte, 1)) return false;
238	
239	    g_current_mac_register = mac_byte;
240	    return true;
241	}
