301	/* ============================================================================
302	 * Pixel Data Transmission
303	 * ========================================================================== */
304	
305	bool hal_gram_write_pixels(const uint8_t *pixel_buffer,
306	                           uint32_t pixel_count,
307	                           hal_pixel_format_t pixel_format)
308	{
309	    if (pixel_buffer == NULL || pixel_count == 0) return false;
310	
311	    size_t bytes_per_pixel;
312	    switch (pixel_format) {
313	        case PIXEL_FORMAT_12BIT: bytes_per_pixel = 2; break;
314	        case PIXEL_FORMAT_16BIT: bytes_per_pixel = 2; break;
315	        case PIXEL_FORMAT_18BIT: bytes_per_pixel = 3; break;
316	        default: return false;
317	    }
318	
319	    return spi_transmit_bulkdata(pixel_buffer,
320	                                 (size_t)pixel_count * bytes_per_pixel);
321	}
