323	bool hal_gram_read_pixels(uint8_t *pixel_buffer,
324	                          uint32_t pixel_count,
325	                          hal_pixel_format_t pixel_format)
326	{
327	    if (pixel_buffer == NULL || pixel_count == 0) return false;
328	
329	    size_t bytes_per_pixel;
330	    switch (pixel_format) {
331	        case PIXEL_FORMAT_12BIT: bytes_per_pixel = 2; break;
332	        case PIXEL_FORMAT_16BIT: bytes_per_pixel = 2; break;
333	        case PIXEL_FORMAT_18BIT: bytes_per_pixel = 3; break;
