341	bool hal_fill_rectangle_solid(uint16_t x_start, uint16_t x_end,
342	                              uint16_t y_start, uint16_t y_end,
343	                              uint16_t color_rgb565)
344	{
345	    if (!hal_window_address_set(x_start, x_end, y_start, y_end)) return false;
346	    if (!hal_gram_write_start()) return false;
347	
348	    uint32_t width  = (uint32_t)(x_end - x_start) + 1;
349	    uint32_t height = (uint32_t)(y_end - y_start) + 1;
350	
351	    uint8_t color_hi = (uint8_t)((color_rgb565 >> 8) & 0xFF);
352	    uint8_t color_lo = (uint8_t)(color_rgb565 & 0xFF);
353	
354	    /* Build a single row buffer (max 320 px × 2 bytes = 640 bytes) and
355	     * send it once per row — 480 transactions instead of 153,600. */
356	    uint8_t row_buf[320 * 2];
357	    uint32_t i;
358	    for (i = 0; i < width && i < 320U; i++) {
359	        row_buf[i * 2]     = color_hi;
360	        row_buf[i * 2 + 1] = color_lo;
361	    }
362	
363	    uint32_t row;
364	    for (row = 0; row < height; row++) {
365	        if (!spi_transmit_bulkdata(row_buf, width * 2)) return false;
366	    }
367	
368	    return true;
369	}
