446	{
447	    /* Positive Gamma Control — Datasheet Section 5.3.33 (0xE0), 15 bytes
448	     * Negative Gamma Control — Datasheet Section 5.3.34 (0xE1), 15 bytes */
449	    if (pos_gamma_table == NULL || neg_gamma_table == NULL) return false;
450	
451	    if (!spi_transmit_command(0xE0)) return false;
452	    if (!spi_transmit_data(pos_gamma_table, 15)) return false;
