460	/* ============================================================================
461	 * Status & Information Queries
462	 * ========================================================================== */
463	
464	bool hal_display_id_read(uint32_t *id_code)
465	{
466	    /* Read ID4 — Datasheet Section 5.3.30 (0xD3)
467	     * Returns 4 bytes: [dummy][ID1][ID2][ID3], expected value 0x009488 */
468	    if (id_code == NULL) return false;
469	
470	    if (!spi_transmit_command(0xD3)) return false;
471	
472	    uint8_t rx_buf[4];
473	    if (!spi_receive_data(rx_buf, 4)) return false;
474	
475	    *id_code = ((uint32_t)rx_buf[1] << 16) |
476	               ((uint32_t)rx_buf[2] <<  8) |
477	                (uint32_t)rx_buf[3];
478	    return true;
479	}
